def _count_baskets(finding_clusters) -> int:
    n = 0
    for c in finding_clusters or []:
        members = (c.get("member_indices") if isinstance(c, dict) else getattr(c, "member_indices", None)) or []
        if len(members) >= 2:
            n += 1
    return n

